16	// MobileServiceRequestedEvent means a customer has requested a new mobile
17	// service.  This will typically happen as a part of order processing.
18	//
19	// Note that ideally, we would generate a service_id and this would also be in
20	// here, but we're not able to do that until more of the overall process is
21	// controlled in the new platform.
22	message MobileServiceRequested {
23	  string order_id = 1;
24	  string quote_id = 2;
25	  string customer_id = 3;  // customer UUID
26	  string tariff_id = 4;
27	  oneof porting {
28	    STAC stac = 5;
29	    PAC pac = 6;
30	  }
31	  string service_id = 7;
32	  SimType sim_type = 8;
33	}
34	
35	// MobileServiceCreated is the logical second part of MobileServiceRequested. At
36	// this point, the requesting is completed and state will begin to be tracked
37	// properly in the new platform.
38	//
39	// Emitted as the result of processing an order
40	// FABRICATION: emit upon discovery of a mobile cli (servicerequestevent)
41	//
42	// Note that ideally, this event would not need to exist and could be merged
43	// with MobileServiceRequested (simply by adding service_id to it).  The reason
44	// it exists for now is that the service_id generation logic (and data required
45	// to do it) only exists in Bill.
46	message MobileServiceCreated {
47	  string service_id = 1;
48	  string order_id = 2;  // optional, will not be present for discovered services
49	  // where platform did not handle provisoning
50	  string customer_id = 3;  // Customer UUID
51	  string tariff_id = 4;
52	  // This existing purely for integrations with bill and should not be consumed
53	  // otherwise
54	  string bill_service_ref = 5 [deprecated = true];
55	}
